INSERT INTO public.posts VALUES ('6e8c4048-b2a1-4f7a-a503-433a103b8ce9', 'Cách mở rộng vốn từ vựng học thuật hiệu quả', 'demo-blog-tu-vung-hoc-thuat', '<p>Phương pháp học từ theo cụm và ngữ cảnh thay vì học vẹt từng từ.</p>', 'Phương pháp học từ theo cụm và ngữ cảnh thay vì học vẹt từng từ.', NULL, 'draft', false, 0, '[]', '{"demo_blog": true}', '["Blog"]', '2026-05-25 00:00:00+00', '2026-06-04 14:23:28.085353+00', 'writing', '["Synonyms"]', false);
INSERT INTO public.posts VALUES ('a043510b-e61e-46fa-a517-5e38adba2198', '5 thói quen luyện nghe tiếng Anh mỗi ngày', 'demo-blog-thoi-quen-nghe', '<p>Những thói quen nhỏ giúp tai bạn quen dần với tốc độ và ngữ điệu bản xứ.</p>', 'Những thói quen nhỏ giúp tai bạn quen dần với tốc độ và ngữ điệu bản xứ.', NULL, 'draft', false, 0, '[]', '{"demo_blog": true}', '["Blog"]', '2026-05-28 00:00:00+00', '2026-06-04 14:23:28.085353+00', 'listening', '["Note-taking"]', false);
INSERT INTO public.posts VALUES ('df0fdfd1-669f-4cdb-8bf2-867aed160288', 'Chinh phục Section 4 IELTS Listening: Bí kíp ăn trọn điểm', 'demo-listening-section-4', '<p>Section 4 thường là phần khó nhất trong bài thi Listening với tốc độ nhanh và nhiều từ vựng học thuật. Hướng dẫn này sẽ cung cấp chiến thuật chi tiết để bạn không bị lạc trôi và tự tin chinh phục.</p><p>Nội dung demo.</p>', 'Section 4 thường là phần khó nhất trong bài thi Listening với tốc độ nhanh và nhiều từ vựng học thuật. Hướng dẫn này sẽ cung cấp chiến thuật chi tiết để bạn không bị lạc trôi và tự tin chinh phục.', NULL, 'draft', false, 0, '[]', '{"demo_prediction": true}', '["IELTS Prediction"]', '2023-10-12 00:00:00+00', '2026-06-04 09:10:13.902879+00', 'listening', '["Multiple Choice", "Note-taking", "Synonyms"]', true);
INSERT INTO public.posts VALUES ('1bd06bf4-0cec-440f-84ca-841f0d18d091', 'Tâm lý phòng thi: giữ bình tĩnh để đạt điểm tối đa', 'demo-blog-tam-ly-phong-thi', '<p>Mẹo kiểm soát lo lắng và phân bổ thời gian hợp lý trong ngày thi.</p>', 'Mẹo kiểm soát lo lắng và phân bổ thời gian hợp lý trong ngày thi.', NULL, 'draft', false, 0, '[]', '{"demo_blog": true}', '["Blog"]', '2026-05-20 00:00:00+00', '2026-06-04 14:23:28.085353+00', 'speaking', '["Fluency"]', false);
INSERT INTO public.posts VALUES ('d8ef2c90-7828-4cf3-a8c1-056969a3ff3c', 'Phân biệt các dạng câu hỏi Listening thường gặp', 'demo-blog-ls-dang-cau-hoi', '<p>Tổng hợp các dạng câu hỏi và cách tiếp cận từng dạng.</p>', 'Tổng hợp các dạng câu hỏi và cách tiếp cận từng dạng.', NULL, 'draft', false, 0, '[]', '{"demo_blog": true}', '["Blog"]', '2026-05-27 00:00:00+00', '2026-06-04 14:28:25.422282+00', 'listening', '["Multiple Choice", "Map Labeling"]', false);
INSERT INTO public.posts VALUES ('eeb87bca-3c91-4be0-b3b6-e0f357ed69fc', 'Cách take note hiệu quả trong Listening Section 3 & 4', 'demo-listening-take-note', '<p>Kỹ thuật ghi chú nhanh giúp bạn bắt trọn key words trong các phần nghe khó nhất.</p><p>Nội dung demo.</p>', 'Kỹ thuật ghi chú nhanh giúp bạn bắt trọn key words trong các phần nghe khó nhất.', NULL, 'draft', false, 0, '[]', '{"demo_prediction": true}', '["IELTS Prediction"]', '2023-10-01 00:00:00+00', '2026-06-04 09:10:13.902879+00', 'listening', '["Note-taking", "Synonyms"]', false);
INSERT INTO public.posts VALUES ('95914592-f3dc-4873-806a-6f77405876ec', 'Từ vựng miêu tả xu hướng (Trends) cần biết', 'demo-writing-trends-vocab', '<p>Nâng cấp từ vựng miêu tả biểu đồ đường, cột để gây ấn tượng với giám khảo và cải thiện điểm.</p><p>Nội dung demo.</p>', 'Nâng cấp từ vựng miêu tả biểu đồ đường, cột để gây ấn tượng với giám khảo và cải thiện điểm.', NULL, 'draft', false, 0, '[]', '{"demo_prediction": true}', '["IELTS Prediction"]', '2023-09-28 00:00:00+00', '2026-06-04 09:10:13.902879+00', 'writing', '["Synonyms", "Note-taking", "Predictions 2026"]', false);
INSERT INTO public.posts VALUES ('69e0a76e-94a3-45f1-b8cd-023022820803', 'Kỹ năng Skimming & Scanning tối ưu thời gian', 'demo-reading-skimming-scanning', '<p>Làm thế nào để đọc lướt và quét thông tin nhanh chóng, giải quyết áp lực thời gian.</p><p>Nội dung demo.</p>', 'Làm thế nào để đọc lướt và quét thông tin nhanh chóng, giải quyết áp lực thời gian.', NULL, 'draft', false, 0, '[]', '{"demo_prediction": true}', '["IELTS Prediction"]', '2023-09-28 00:00:00+00', '2026-06-04 09:10:13.902879+00', 'reading', '["Fluency"]', false);
INSERT INTO public.posts VALUES ('06f6757e-d5db-464b-887e-e6ba6aac1199', 'Chiến lược làm dạng bài True/False/Not Given', 'demo-reading-tfng', '<p>Phân biệt rõ ràng giữa False và Not Given để không bị mất điểm oan trong bài thi Đọc.</p><p>Nội dung demo.</p>', 'Phân biệt rõ ràng giữa False và Not Given để không bị mất điểm oan trong bài thi Đọc.', NULL, 'draft', false, 0, '[]', '{"demo_prediction": true}', '["IELTS Prediction"]', '2023-10-05 00:00:00+00', '2026-06-04 09:10:13.902879+00', 'reading', '["Distractors"]', false);
INSERT INTO public.posts VALUES ('6b37f4fa-e86c-4124-a491-4cd37ddb4d5c', 'Cấu trúc ăn điểm cho Task 2 dạng Agree/Disagree', 'demo-writing-agree-disagree', '<p>Hướng dẫn chi tiết cách lập dàn ý và triển khai các đoạn văn body cho dạng bài Agree/Disagree.</p><p>Nội dung demo.</p>', 'Hướng dẫn chi tiết cách lập dàn ý và triển khai các đoạn văn body cho dạng bài Agree/Disagree.', NULL, 'draft', false, 0, '[]', '{"demo_prediction": true}', '["IELTS Prediction"]', '2023-10-12 00:00:00+00', '2026-06-04 09:10:13.902879+00', 'writing', '["Fluency", "Synonyms"]', false);
INSERT INTO public.posts VALUES ('6868becc-8cb6-4b32-90cd-46def748068e', 'Chiến thuật làm bài Map Labeling không bao giờ lạc', 'demo-listening-map-labeling', '<p>Nắm vững các từ vựng chỉ phương hướng và cách theo dõi nhịp độ bài nghe để hoàn thành Map Labeling.</p><p>Nội dung demo.</p>', 'Nắm vững các từ vựng chỉ phương hướng và cách theo dõi nhịp độ bài nghe để hoàn thành Map Labeling.', NULL, 'draft', false, 0, '[]', '{"demo_prediction": true}', '["IELTS Prediction"]', '2023-09-18 00:00:00+00', '2026-06-04 09:10:13.902879+00', 'listening', '["Map Labeling"]', false);
